operation.add:
$this->load->model('extension/module/cyberpunks_shop_option_fields');
$this->model_extension_module_cyberpunks_shop_option_fields->install();
$option_id = $this->model_catalog_option->addOption($this->request->post);
$this->model_extension_module_cyberpunks_shop_option_fields->saveOptionMode($option_id, $this->request->post);
$this->model_extension_module_cyberpunks_shop_option_fields->saveOptionFieldValues($option_id, isset($this->request->post['cyberpunks_option_custom_fields']) ? $this->request->post['cyberpunks_option_custom_fields'] : array());

$this->load->model('extension/module/cyberpunks_shop_option_fields');
$this->model_extension_module_cyberpunks_shop_option_fields->install();
$this->model_catalog_option->editOption($this->request->get['option_id'], $this->request->post);
$this->model_extension_module_cyberpunks_shop_option_fields->saveOptionMode((int)$this->request->get['option_id'], $this->request->post);
$this->model_extension_module_cyberpunks_shop_option_fields->saveOptionFieldValues((int)$this->request->get['option_id'], isset($this->request->post['cyberpunks_option_custom_fields']) ? $this->request->post['cyberpunks_option_custom_fields'] : array());

$this->load->model('extension/module/cyberpunks_shop_option_fields');
$this->model_extension_module_cyberpunks_shop_option_fields->install();
$cyberpunks_custom_fields = $this->model_extension_module_cyberpunks_shop_option_fields->getCustomFields(true);
$data['cyberpunks_option_custom_fields'] = array();
$data['cyberpunks_option_value_custom_field_defs'] = array();
foreach ($cyberpunks_custom_fields as $cyberpunks_custom_field) {
	if (isset($cyberpunks_custom_field['scope']) && $cyberpunks_custom_field['scope'] === 'option') {
		$data['cyberpunks_option_custom_fields'][] = $cyberpunks_custom_field;
	} else {
		$data['cyberpunks_option_value_custom_field_defs'][] = $cyberpunks_custom_field;
	}
}

if (isset($this->request->post['cyberpunks_option_mode'])) {
	$data['cyberpunks_option_mode'] = $this->request->post['cyberpunks_option_mode'];
} elseif (!empty($option_info) && isset($option_info['option_id'])) {
	$data['cyberpunks_option_mode'] = $this->model_extension_module_cyberpunks_shop_option_fields->getOptionMode((int)$option_info['option_id']);
} else {
	$data['cyberpunks_option_mode'] = array('show_image' => 1, 'enabled_field_ids' => array());
}

$data['cyberpunks_option_value_custom_fields'] = array();
if (isset($this->request->post['option_value']) && is_array($this->request->post['option_value'])) {
	foreach ($this->request->post['option_value'] as $cyberpunks_option_value_row => $cyberpunks_option_value_data) {
		$data['cyberpunks_option_value_custom_fields'][$cyberpunks_option_value_row] = isset($cyberpunks_option_value_data['cyberpunks_custom_fields']) && is_array($cyberpunks_option_value_data['cyberpunks_custom_fields']) ? $cyberpunks_option_value_data['cyberpunks_custom_fields'] : array();
	}
} elseif (!empty($option_info) && isset($option_info['option_id'])) {
	$data['cyberpunks_option_value_custom_fields'] = $this->model_extension_module_cyberpunks_shop_option_fields->getOptionValueFieldValues((int)$option_info['option_id']);
}

if (isset($this->request->post['cyberpunks_option_custom_fields']) && is_array($this->request->post['cyberpunks_option_custom_fields'])) {
	$data['cyberpunks_option_custom_field_values'] = $this->request->post['cyberpunks_option_custom_fields'];
} elseif (!empty($option_info) && isset($option_info['option_id'])) {
	$data['cyberpunks_option_custom_field_values'] = $this->model_extension_module_cyberpunks_shop_option_fields->getOptionFieldValues((int)$option_info['option_id']);
} else {
	$data['cyberpunks_option_custom_field_values'] = array();
}

$data['entry_cyberpunks_show_image'] = $this->language->get('entry_cyberpunks_show_image');
$data['entry_cyberpunks_custom_fields'] = $this->language->get('entry_cyberpunks_custom_fields');
$data['entry_cyberpunks_option_fields'] = $this->language->get('entry_cyberpunks_option_fields');

$cyberpunks_custom_fields = isset($option_value['cyberpunks_custom_fields']) && is_array($option_value['cyberpunks_custom_fields']) ? $option_value['cyberpunks_custom_fields'] : array();
foreach ($cyberpunks_custom_fields as $field_id => $field_value) {
	$field_id = (int)$field_id;
	if ($field_id <= 0) {
		continue;
	}
	$this->db->query("INSERT INTO `" . DB_PREFIX . "cyberpunks_option_custom_field_value` SET option_id = '" . (int)$option_id . "', option_value_id = '" . (int)$option_value_id . "', field_id = '" . $field_id . "', value = '" . $this->db->escape((string)$field_value) . "', date_modified = NOW()");
}

if (!(int)$option_value_id && !empty($option_value['option_value_id'])) {
	$option_value_id = (int)$option_value['option_value_id'];
}

$this->db->query("DELETE FROM `" . DB_PREFIX . "cyberpunks_option_custom_field_value` WHERE option_value_id = '" . (int)$option_value_id . "'");
$cyberpunks_custom_fields = isset($option_value['cyberpunks_custom_fields']) && is_array($option_value['cyberpunks_custom_fields']) ? $option_value['cyberpunks_custom_fields'] : array();
foreach ($cyberpunks_custom_fields as $field_id => $field_value) {
	$field_id = (int)$field_id;
	if ($field_id <= 0) {
		continue;
	}
	$this->db->query("INSERT INTO `" . DB_PREFIX . "cyberpunks_option_custom_field_value` SET option_id = '" . (int)$option_id . "', option_value_id = '" . (int)$option_value_id . "', field_id = '" . $field_id . "', value = '" . $this->db->escape((string)$field_value) . "', date_modified = NOW()");
}

    html += '  <td class="text-center cyberpunks-image-column"><a href="" id="thumb-image' + option_value_row + '" data-toggle="image" class="img-thumbnail"><img src="{{ placeholder }}" alt="" title="" data-placeholder="{{ placeholder }}" /></a><input type="hidden" name="option_value[' + option_value_row + '][image]" value="" id="input-image' + option_value_row + '" /></td>';
	{% for field in cyberpunks_option_value_custom_field_defs %}
	{% if field.field_type == 'textarea' %}
    html += '  <td class="text-left cyberpunks-custom-field-column cyberpunks-custom-field-column-{{ field.field_id }}"><textarea name="option_value[' + option_value_row + '][cyberpunks_custom_fields][{{ field.field_id }}]" rows="2" class="form-control"></textarea></td>';
	{% elseif field.field_type == 'boolean' %}
    html += '  <td class="text-left cyberpunks-custom-field-column cyberpunks-custom-field-column-{{ field.field_id }}"><input type="hidden" name="option_value[' + option_value_row + '][cyberpunks_custom_fields][{{ field.field_id }}]" value="0" /><input type="checkbox" name="option_value[' + option_value_row + '][cyberpunks_custom_fields][{{ field.field_id }}]" value="1" /></td>';
	{% else %}
    html += '  <td class="text-left cyberpunks-custom-field-column cyberpunks-custom-field-column-{{ field.field_id }}"><input type="text" name="option_value[' + option_value_row + '][cyberpunks_custom_fields][{{ field.field_id }}]" value="" class="form-control" /></td>';
	{% endif %}
	{% endfor %}

function cyberpunksToggleColumns() {
	var showImage = $('#input-cyberpunks-show-image').is(':checked');
	$('.cyberpunks-image-column').toggle(showImage);

	{% for field in cyberpunks_option_value_custom_field_defs %}
	var showField{{ field.field_id }} = $('#input-cyberpunks-show-field-{{ field.field_id }}').is(':checked');
	$('.cyberpunks-custom-field-column-{{ field.field_id }}').toggle(showField{{ field.field_id }});
	{% endfor %}
}

$('#input-cyberpunks-show-image').on('change', cyberpunksToggleColumns);
{% for field in cyberpunks_option_value_custom_field_defs %}
$('#input-cyberpunks-show-field-{{ field.field_id }}').on('change', cyberpunksToggleColumns);
{% endfor %}
{% for field in cyberpunks_option_custom_fields %}
$('#input-cyberpunks-show-option-field-{{ field.field_id }}').on('change', function() {
	$('.cyberpunks-option-field-input-{{ field.field_id }}').toggle($(this).is(':checked'));
});
$('.cyberpunks-option-field-input-{{ field.field_id }}').toggle($('#input-cyberpunks-show-option-field-{{ field.field_id }}').is(':checked'));
{% endfor %}
cyberpunksToggleColumns();

$_['entry_cyberpunks_show_image'] = 'Display mode';
$_['entry_cyberpunks_custom_fields'] = 'Custom option value fields';
$_['entry_cyberpunks_option_fields'] = 'Custom option fields';

$cyberpunks_option_fields = array();
$cyberpunks_option_fields_tables = $this->db->query("SHOW TABLES LIKE '" . $this->db->escape(DB_PREFIX . "cyberpunks_option_custom_field_value") . "'");

if ($cyberpunks_option_fields_tables->num_rows) {
	$cyberpunks_option_fields_query = $this->db->query("SELECT f.field_key, v.value FROM `" . DB_PREFIX . "cyberpunks_option_custom_field_value` v LEFT JOIN `" . DB_PREFIX . "cyberpunks_option_custom_field` f ON (v.field_id = f.field_id) WHERE v.option_id = '" . (int)$product_option['option_id'] . "' AND v.option_value_id = '0' AND f.status = '1'");

	foreach ($cyberpunks_option_fields_query->rows as $cyberpunks_option_field_row) {
		if (!empty($cyberpunks_option_field_row['field_key'])) {
			$cyberpunks_option_fields[$cyberpunks_option_field_row['field_key']] = $cyberpunks_option_field_row['value'];
		}
	}
}

$cyberpunks_fields = array();
$cyberpunks_fields_tables = $this->db->query("SHOW TABLES LIKE '" . $this->db->escape(DB_PREFIX . "cyberpunks_option_custom_field_value") . "'");

if ($cyberpunks_fields_tables->num_rows) {
	$cyberpunks_fields_query = $this->db->query("SELECT f.field_key, v.value FROM `" . DB_PREFIX . "cyberpunks_option_custom_field_value` v LEFT JOIN `" . DB_PREFIX . "cyberpunks_option_custom_field` f ON (v.field_id = f.field_id) WHERE v.option_value_id = '" . (int)$product_option_value['option_value_id'] . "' AND f.status = '1'");

	foreach ($cyberpunks_fields_query->rows as $cyberpunks_field_row) {
		if (!empty($cyberpunks_field_row['field_key'])) {
			$cyberpunks_fields[$cyberpunks_field_row['field_key']] = $cyberpunks_field_row['value'];
		}
	}
}
